from pathlib import Path
import re
path=Path(r'D:\Projects\bazi-portal\names.html')
text=path.read_text(encoding='utf-8')
text=text.replace(".subline{display:flex;justify-content:space-between;gap:10px;flex-wrap:wrap}.section-gap{margin-top:20px}\n",".subline{display:flex;justify-content:space-between;gap:10px;flex-wrap:wrap}.section-gap{margin-top:20px}\n.pattern-card{scroll-margin-top:110px}.pattern-card.active-target{border-color:rgba(255,255,255,.45);box-shadow:0 0 0 1px rgba(255,255,255,.18),0 18px 48px rgba(0,0,0,.28)}.name-line{margin-top:12px;padding:16px 16px 14px;border-radius:20px;border:1px solid rgba(255,255,255,.08);background:linear-gradient(180deg,rgba(255,255,255,.08),rgba(255,255,255,.04))}.name-line .name-calligraphy{font-size:42px;line-height:1.05;font-weight:800;letter-spacing:1.2px}.name-line .small{display:block;margin-top:8px;color:#c9d3ea;font-size:14px}.name-line .score{font-size:18px;font-weight:800;white-space:nowrap}.name-line .note{margin-top:12px;line-height:1.8;color:#f4f7ff;font-size:14px}.detail-toggle{padding:8px 12px!important;font-size:12px!important;min-width:84px}\n",1)
pattern=re.compile(r"const patterns=\[.*?render\(\);</script></body></html>",re.S)
replacement="""const patterns=['���','����','ľ���','ˮ���','������','����']; const container=document.getElementById('patterns'); const maleBtn=document.getElementById('maleBtn'); const femaleBtn=document.getElementById('femaleBtn'); const body=document.body; const topbar=document.getElementById('namesTopbar'); const MOBILE_BATCH=12; const renderState={��:{},Ů:{}}; const genderScrollMemory={��:null,Ů:null}; let suppressScrollMemoryWrite=false; let activePattern=''; function isMobile(){ return window.innerWidth<=720; } function getBatch(pattern){ const key=currentGender; const total=(currentGender==='��'?topData[pattern].boys:topData[pattern].girls).length; if(!isMobile()) return total; const now=renderState[key][pattern]||MOBILE_BATCH; return Math.min(now,total); } function ensureMore(pattern){ const key=currentGender; const total=(currentGender==='��'?topData[pattern].boys:topData[pattern].girls).length; const now=renderState[key][pattern]||MOBILE_BATCH; if(now<total) renderState[key][pattern]=Math.min(now+MOBILE_BATCH,total); } function entryHtml(r,p){ const mobile=isMobile(); return `<div class="name-line"><div class="subline"><div><div class="name-calligraphy" style="${patternStyle[p]}">${r.name}</div><span class="small">${r.pinyin}</span></div><div style="display:flex;flex-direction:column;align-items:flex-end;gap:8px"><div class="score">${r.score} ��</div>${mobile?'<button class="btn detail-toggle" type="button" data-detail-toggle="1">չ������</button>':''}</div></div><div class="note" ${mobile?'data-detail-body="1" style="display:none"':''}><b>���У�</b>${r.wuxing}<br><b class="meaning">�����˼��</b><span class="meaning">${r.meaning}</span><br><b>������</b>${r.source}<br><span class="reason"><b>�������ɣ�</b><strong>���� ${r.score}</strong>��${r.reason.replace(/^����\s*\d+[.:��]?/,'')}</span></div></div>`; } function cardHtml(p){ const list=(currentGender==='��'?topData[p].boys:topData[p].girls); const visible=list.slice(0,getBatch(p)); return `<article class="card pattern-card ${activePattern===p?'active-target':''}" id="${encodeURIComponent(p)}" data-pattern="${p}" style="background-image:${patternBg[p]}"><div class="pattern-headline"><div class="pattern-meta-left"><span class="badge">${patternDirection[p]}</span></div><div class="pattern-title-big" style="${patternStyle[p]}">${p}</div><div class="pattern-meta-right"><span class="badge">${list.length} ������</span></div></div>${visible.map(r=>entryHtml(r,p)).join('')}${visible.length<list.length?`<div class="bottom-actions"><button class="btn" data-more="${p}">�ٿ� ${Math.min(MOBILE_BATCH,list.length-visible.length)} ��</button></div>`:''}</article>`; }  function bindAutoLoad(){ if(!isMobile()) return; const io=new IntersectionObserver(entries=>{ entries.forEach(entry=>{ if(!entry.isIntersecting) return; const card=entry.target.closest('.pattern-card'); if(!card) return; const p=card.getAttribute('data-pattern'); const list=(currentGender==='��'?topData[p].boys:topData[p].girls); const shown=getBatch(p); if(shown<list.length){ ensureMore(p); const oldTop=window.scrollY; render(false); window.scrollTo({top:oldTop,behavior:'auto'}); } }); },{root:null,rootMargin:'0px 0px 320px 0px',threshold:0.01}); document.querySelectorAll('.pattern-card').forEach(card=>{ const lines=card.querySelectorAll('.name-line'); const target=lines[Math.max(0,lines.length-2)]||card; io.observe(target); }); window._namesAutoLoadObserver=io; container.querySelectorAll('[data-more]').forEach(btn=>btn.onclick=()=>{ const p=btn.getAttribute('data-more'); if(!p) return; ensureMore(p); const oldTop=window.scrollY; render(false); window.scrollTo({top:oldTop,behavior:'auto'}); }); container.querySelectorAll('[data-detail-toggle]').forEach(btn=>btn.onclick=()=>{ const item=btn.closest('.name-line'); const detail=item&&item.querySelector('[data-detail-body]'); if(!detail) return; const open=detail.style.display!=='none'; detail.style.display=open?'none':'block'; btn.textContent=open?'չ������':'��������'; }); } function updateTopbar(){ if(!suppressScrollMemoryWrite){ genderScrollMemory[currentGender]=window.scrollY||window.pageYOffset||0; } if(window._namesAutoLoadObserver && !isMobile()){ try{window._namesAutoLoadObserver.disconnect()}catch(e){} } const compact=window.scrollY>32; topbar.classList.toggle('compact',compact); } function getPatternFromHash(){ const raw=decodeURIComponent((location.hash||'').replace(/^#/,'')); return patterns.find(p=>p===raw)||''; } function jumpToPattern(pattern,behavior='smooth'){ if(!pattern) return; activePattern=pattern; const node=container.querySelector(`[data-pattern="${pattern}"]`); if(!node) return; container.querySelectorAll('.pattern-card.active-target').forEach(el=>el.classList.remove('active-target')); node.classList.add('active-target'); node.scrollIntoView({block:'start',behavior}); } function syncHashTarget(behavior='auto'){ const pattern=getPatternFromHash(); if(!pattern) return; activePattern=pattern; requestAnimationFrame(()=>jumpToPattern(pattern,behavior)); } function switchGender(nextGender){ if(nextGender===currentGender) return; const prevGender=currentGender; genderScrollMemory[prevGender]=window.scrollY||window.pageYOffset||0; currentGender=nextGender; body.className=nextGender==='��'?'names-page theme-male':'names-page theme-female'; maleBtn.classList.toggle('active', nextGender==='��'); femaleBtn.classList.toggle('active', nextGender==='Ů'); suppressScrollMemoryWrite=true; render(false); requestAnimationFrame(()=>{ const target=getPatternFromHash(); if(target){ jumpToPattern(target,'auto'); } else { const targetY=genderScrollMemory[nextGender]==null?0:genderScrollMemory[nextGender]; window.scrollTo({top:targetY,behavior:'auto'}); } requestAnimationFrame(()=>{ suppressScrollMemoryWrite=false; updateTopbar(); }); }); } function render(resetScroll=false){ container.innerHTML = patterns.map(p=>cardHtml(p)).join(''); bindAutoLoad(); updateTopbar(); if(resetScroll){ suppressScrollMemoryWrite=true; window.scrollTo({top:0,behavior:'auto'}); requestAnimationFrame(()=>{ suppressScrollMemoryWrite=false; updateTopbar(); }); } syncHashTarget('auto'); } maleBtn.onclick=()=>switchGender('��'); femaleBtn.onclick=()=>switchGender('Ů'); window.addEventListener('scroll', updateTopbar,{passive:true}); window.addEventListener('hashchange', ()=>syncHashTarget('smooth')); window.addEventListener('resize', ()=>{ genderScrollMemory[currentGender]=window.scrollY||window.pageYOffset||0; suppressScrollMemoryWrite=true; render(false); requestAnimationFrame(()=>window.scrollTo({top:genderScrollMemory[currentGender]||0,behavior:'auto'})); requestAnimationFrame(()=>{ suppressScrollMemoryWrite=false; updateTopbar(); syncHashTarget('auto'); }); }); render();</script></body></html>"""
text, n=pattern.subn(lambda m: replacement,text,1)
if n!=1: raise SystemExit('script replace failed')
path.write_text(text,encoding='utf-8')
print('patched names')
